import {Calendar} from '@gravity-ui/date-components';
import {dateTimeParse} from '@gravity-ui/date-utils';

<Calendar
  value={selectedDate}
  onUpdate={(date) => setSelectedDate(date)}
  minValue={dateTimeParse('2024-01-01')}
  maxValue={dateTimeParse('2024-12-31')}
/>

import {DateField} from '@gravity-ui/date-components';

<DateField
  label="Birth date"
  format="DD.MM.YYYY"
  hasClear
  value={date}
  onUpdate={(date) => setDate(date)}
/>

import {DatePicker} from '@gravity-ui/date-components';

<DatePicker
  label="Event date"
  format="MMMM D, YYYY"
  hasClear
  value={date}
  onUpdate={(date) => setDate(date)}
/>

import {RelativeDateField} from '@gravity-ui/date-components';

<RelativeDateField
  label="From"
  placeholder="now-7d"
  hasClear
  value={fromDate}
  onUpdate={(value) => setFromDate(value)}
/>

import {RelativeDatePicker} from '@gravity-ui/date-components';

<RelativeDatePicker
  label="Start date"
  hasClear
  value={startDate}
  onUpdate={(value) => setStartDate(value)}
/>
